### Step 2: Add API Tests

Continue adding to `test_chatbot.py`:

```python
class TestChatAPI:
    """Tests for the /chat API endpoint."""

    @pytest.fixture
    def client(self):
        """Create a test client for the Flask app."""
        app.config['TESTING'] = True
        with app.test_client() as client:
            yield client

    def test_empty_message_rejected(self, client):
        """TC-002: Empty messages should return an error."""
        response = client.post('/chat', 
            json={'message': ''}
        )
        data = response.get_json()
        assert 'Please enter a message' in data['response']

    def test_long_message_rejected(self, client):
        """TC-003: Messages over 500 chars should return an error."""
        long_message = 'a' * 501
        response = client.post('/chat', 
            json={'message': long_message}
        )
        data = response.get_json()
        assert 'too long' in data['response'].lower()

    def test_normal_message_gets_response(self, client):
        """TC-001: Normal messages should get a bot response."""
        response = client.post('/chat', 
            json={'message': 'Hello'}
        )
        data = response.get_json()
        assert 'response' in data
        assert len(data['response']) > 0
```

### Updated Chat Route

Replace your `/chat` route with this improved version:

```python
@app.route('/chat', methods=['POST'])
def chat():
    """Handle chat messages and return bot responses."""
    data = request.get_json()
    raw_message = data.get('message', '')

    # Sanitise and validate input
    user_message = sanitise_input(raw_message)

    if user_message is None:
        if not raw_message or not raw_message.strip():
            return jsonify({'response': 'Please enter a message!'})
        else:
            return jsonify({'response': 'Message too long! Please keep it under 500 characters.'})

    # Safety check for crisis keywords (use original for better detection)
    if check_for_crisis(raw_message):
        return jsonify({'response': CRISIS_RESPONSE})

    # Get the chatbot's response
    bot_response = chatbot.get_response(user_message)

    return jsonify({'response': str(bot_response)})
```

### What This Improves

| Before | After |
|--------|-------|
| `"   "` accepted as valid | Rejected (whitespace only) |
| `<script>bad</script>` passed through | HTML tags stripped |
| No input sanitisation | Clean, safe input |
